SELECT artist, title
FROM metadata
WHERE date_created = (SELECT MAX(date_created) FROM metadata);

SELECT COUNT(*) AS active_exhibition_count
FROM virtual_exhibitions
WHERE is_active = 1;

SELECT total_views
FROM virtual_exhibitions
WHERE exhibition_name = 'Modern Art Showcase';

SELECT COUNT(*) AS active_set_count
FROM image_sets
WHERE is_active = 1;
